package inputbox

import (
	"testing"

	tea "charm.land/bubbletea/v2"
	"github.com/stretchr/testify/assert"

	"github.com/dlvhdr/gh-dash/v4/internal/tui/context"
	"github.com/dlvhdr/gh-dash/v4/internal/tui/theme"
)

func createTestContext() *context.ProgramContext {
	ctx := &context.ProgramContext{
		Theme: theme.ParseTheme(nil),
	}
	ctx.Styles = context.InitStyles(ctx.Theme)
	return ctx
}

func TestPasteMsg(t *testing.T) {
	ctx := createTestContext()
	m := NewModel(ctx)

	pasteText := "this should paste into gh-dash"
	msg := tea.PasteMsg{Content: pasteText}

	m, _ = m.Update(msg)

	assert.Equal(t, pasteText, m.Value(),
		"paste message should insert text into the inputbox")
}

func TestPasteMsg_Append(t *testing.T) {
	ctx := createTestContext()
	m := NewModel(ctx)

	// First type some text
	m, _ = m.Update(tea.KeyPressMsg{Text: "hello "})
	assert.Equal(t, "hello ", m.Value())

	// Then paste
	msg := tea.PasteMsg{Content: "world"}
	m, _ = m.Update(msg)

	assert.Equal(t, "hello world", m.Value(),
		"paste message should append to existing text")
}

func TestPasteMsg_EmptyText(t *testing.T) {
	ctx := createTestContext()
	m := NewModel(ctx)

	msg := tea.PasteMsg{Content: ""}
	m, _ = m.Update(msg)

	assert.Equal(t, "", m.Value(),
		"empty paste should result in empty value")
}

