func TestPasteInCommentMode(t *testing.T) {
	c := newTestController(t)
	c, _ = c.Enter(EnterOptions{
		Mode:                             ModeComment,
		Prompt:                           "comment",
		Source:                           dataautocomplete.UserMentionSource{},
		Repo:                             testRepo(),
		SuggestionKind:                   SuggestionUsers,
		EnterFetch:                       FetchNone,
		ConfirmDiscardOnCancel:           true,
		HideAutocompleteWhenContextEmpty: true,
	})

	c, _, _, handled := c.Update(tea.PasteMsg{Content: "this should paste into gh-dash"})
	require.True(t, handled)
	require.Equal(t, "this should paste into gh-dash", c.inputBox.Value())
}

func TestPasteInInactiveMode(t *testing.T) {
	c := newTestController(t)

	c, _, _, handled := c.Update(tea.PasteMsg{Content: "should not paste"})
	require.False(t, handled)
	require.Equal(t, "", c.inputBox.Value())
}

